namespace sv_219bca1c952449b4ad3f90b2c56571fd.Services;

public sealed class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new("WH-A", "Warehouse A"),
        new("WH-B", "Warehouse B"),
        new("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

public sealed record WarehouseInfo(string Id, string Name);

namespace sv_219bca1c952449b4ad3f90b2c56571fd.Services;

public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database query with a random result per warehouse.
        int count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

@using sv_219bca1c952449b4ad3f90b2c56571fd.Services
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="d-flex align-items-center">
    <label class="me-2 mb-0 text-nowrap fw-semibold">Warehouse:</label>
    <select class="form-select form-select-sm" style="width: auto;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        WarehouseState.SetWarehouse(e.Value?.ToString() ?? "");
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_219bca1c952449b4ad3f90b2c56571fd.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

@if (_count.HasValue && _count.Value > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@_count.Value</span>
}

@code {
    private int? _count;

    // Invoked by the Dashboard's polling timer to push new data.
    public async Task RefreshAsync()
    {
        _count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        await InvokeAsync(StateHasChanged);
    }

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        await RefreshAsync();
    }

    private async void OnWarehouseChanged()
    {
        await RefreshAsync();
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_219bca1c952449b4ad3f90b2c56571fd.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h3 class="mb-3">📦 Warehouse Dashboard — @WarehouseState.CurrentWarehouseName</h3>

<div class="row g-3">
    <div class="col-md-4">
        <div class="card border-danger">
            <div class="card-body text-center">
                <h5 class="card-title text-danger">Low-Stock Alerts</h5>
                <p class="display-4 fw-bold text-danger">@(_lowStockCount?.ToString() ?? "…")</p>
                <small class="text-muted">items below minimum level</small>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Site</h5>
                <p class="display-6">@WarehouseState.CurrentWarehouseName</p>
                <small class="text-muted">@WarehouseState.CurrentWarehouseId</small>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6">🟢 Active</p>
                <small class="text-muted">refreshes every 10 s</small>
            </div>
        </div>
    </div>
</div>

@code {
    private int? _lowStockCount;
    private CancellationTokenSource? _cts;

    // The sidebar AlertBadge registers itself here so the polling loop can push updates.
    [CascadingParameter]
    public AlertBadge? SidebarBadge { get; set; }

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        _cts = new CancellationTokenSource();
        await FetchAndNotify();
        _ = PollAsync(_cts.Token);
    }

    private async Task FetchAndNotify()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        StateHasChanged();

        if (SidebarBadge is not null)
            await SidebarBadge.RefreshAsync();
    }

    private async Task PollAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await InvokeAsync(async () => await FetchAndNotify());
            }
        }
        catch (OperationCanceledException) { }
    }

    private async void OnWarehouseChanged()
    {
        await InvokeAsync(async () => await FetchAndNotify());
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

