<div class="row g-3">
    <div class="col-md-4">
        <div class="card border-danger">
            <div class="card-body text-center">
                <h5 class="card-title text-danger">Low-Stock Alerts</h5>
                <p class="display-4 fw-bold text-danger">@(_lowStockCount?.ToString() ?? "…")</p>
                <small class="text-muted">items below minimum level</small>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Site</h5>
                <p class="display-6">@WarehouseState.CurrentWarehouseName</p>
                <small class="text-muted">@WarehouseState.CurrentWarehouseId</small>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6">🟢 Active</p>
                <small class="text-muted">refreshes every 10 s</small>
            </div>
        </div>
    </div>
</div>

@code {
    private int? _lowStockCount;
    private CancellationTokenSource? _cts;

    // The sidebar AlertBadge registers itself here so the polling loop can push updates.
    [CascadingParameter]
    public AlertBadge? SidebarBadge { get; set; }

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        _cts = new CancellationTokenSource();
        await FetchAndNotify();
        _ = PollAsync(_cts.Token);
    }

    private async Task FetchAndNotify()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        StateHasChanged();

        if (SidebarBadge is not null)
            await SidebarBadge.RefreshAsync();
    }

    private async Task PollAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await InvokeAsync(async () => await FetchAndNotify());
            }
        }
        catch (OperationCanceledException) { }
    }

    private async void OnWarehouseChanged()
    {
        await InvokeAsync(async () => await FetchAndNotify());
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

